import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const apiKey = process.env.API_KEY || '';

// Initialize only if key exists to avoid immediate errors, though usage will check
const ai = apiKey ? new GoogleGenAI({ apiKey }) : null;

const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

/**
 * Helper function to retry async operations with exponential backoff.
 * Handles 429 (Rate Limit) and 503 (Overloaded).
 */
async function retryWithBackoff<T>(
  fn: () => Promise<T>,
  retries = 3,
  delay = 2000
): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const isRateLimit = 
      error.status === 429 || 
      error.code === 429 || 
      (error.message && typeof error.message === 'string' && error.message.includes("RESOURCE_EXHAUSTED"));

    const isOverloaded =
      error.status === 503 ||
      error.code === 503 ||
      (error.message && typeof error.message === 'string' && error.message.toLowerCase().includes("overloaded"));

    if (retries > 0 && (isRateLimit || isOverloaded)) {
      const nextDelay = isRateLimit ? Math.max(delay, 4000) : delay;
      console.warn(`API ${isRateLimit ? 'Rate Limit' : 'Overloaded'}. Retrying in ${nextDelay}ms... (${retries} attempts left)`);

      await wait(nextDelay);
      return retryWithBackoff(fn, retries - 1, nextDelay * 2);
    }
    throw error;
  }
}

/**
 * Converts a base64 string or URL to a format suitable for the API.
 */
async function urlToBase64(url: string): Promise<string> {
  if (url.startsWith('data:')) {
    return url.split(',')[1];
  }

  const fetchBlob = async (targetUrl: string): Promise<Blob> => {
    const response = await fetch(targetUrl);
    if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
    return await response.blob();
  };

  const strategies = [
    { name: 'Direct', getUrl: (u: string) => u },
    { name: 'Weserv', getUrl: (u: string) => `https://images.weserv.nl/?url=${encodeURIComponent(u)}&output=png&il` },
    { name: 'CorsProxy', getUrl: (u: string) => `https://corsproxy.io/?${encodeURIComponent(u)}` },
    { name: 'AllOrigins', getUrl: (u: string) => `https://api.allorigins.win/raw?url=${encodeURIComponent(u)}` }
  ];

  for (const strategy of strategies) {
    try {
      const blob = await fetchBlob(strategy.getUrl(url));
      return await new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onloadend = () => {
          const result = reader.result as string;
          resolve(result.split(',')[1]);
        };
        reader.onerror = reject;
        reader.readAsDataURL(blob);
      });
    } catch (e) {
      console.warn(`Fetch strategy '${strategy.name}' failed for ${url}`, e);
    }
  }

  throw new Error("Could not download image. Please upload it directly.");
}

/**
 * Analyzes for Suncatcher/Ornament strategy before generation.
 */
async function analyzeForSuncatcherTheme(base64Image: string, keyword: string): Promise<string> {
  if (!ai) throw new Error("API Key not found.");

  const analysisPrompt = `
    Analyze this suncatcher/ornament image and the keyword "${keyword}".
    Identify:
    1. The core theme/subject inside the frame.
    2. The style of the stained glass (e.g., floral, animal, abstract).
    3. The color palette.

    Return a brief description of a FRESH, NEW variation of this subject that would fit perfectly inside the exact same frame.
    Keep the "vibe" but change the specific details (e.g., if it's a cat, describe a different breed or pose).
  `;

  try {
    const response = await retryWithBackoff<GenerateContentResponse>(() => 
      ai.models.generateContent({
        model: 'gemini-3-flash-preview', 
        contents: {
          parts: [
            { inlineData: { mimeType: 'image/png', data: base64Image } },
            { text: analysisPrompt }
          ]
        }
      })
    );
    return response.text || `A beautiful stained glass variation of ${keyword}.`;
  } catch (error) {
    return `A premium stained glass design for ${keyword}.`;
  }
}

/**
 * Slot 1: Lifestyle Mockup (Generates 3 distinct high-end variations)
 */
export const generateRedesign = async (
  keyword: string, 
  originalImageSrc: string,
  ideas: string[] = []
): Promise<string[]> => {
  if (!ai) throw new Error("API Key not found.");

  let base64Image: string;
  try {
    base64Image = await urlToBase64(originalImageSrc);
  } catch (e: any) {
    throw new Error(`Image processing failed: ${e.message}`);
  }

  const contexts = [
    "Modern minimalist sunlit living room with large windows.",
    "Cozy reading nook with warm morning light and plants.",
    "Professional studio photography with soft bokeh and spring flowers."
  ];

  const successfulImages: string[] = [];

  for (const context of contexts) {
    const prompt = `
      Create a high-end lifestyle mockup of the provided suncatcher.
      SCENE: ${context}
      CONSTRAINTS:
      - Keep the suncatcher frame and design 100% identical to the input.
      - Place it hanging in front of a window or over a light wood table.
      - Use shallow depth of field (85mm f/1.8), sharp focus on the suncatcher.
      - Diffused morning sunlight from back-left with soft reflections.
      - Professional aesthetic, crisp details.
    `;

    try {
        if (successfulImages.length > 0) await wait(2000);
        const img = await generateImage(base64Image, prompt);
        successfulImages.push(img);
    } catch (err) {
        console.error("Failed variation:", err);
    }
  }

  if (successfulImages.length === 0) throw new Error("Generation failed.");
  return successfulImages;
};

/**
 * Slot 2: Master Suncatcher Redesign
 * Implements the user's highly specific 100% preservation + interior redesign logic.
 */
export const generateProductConcept = async (
  keyword: string, 
  originalImageSrc: string,
  ideas: string[] = []
): Promise<string> => {
  if (!ai) throw new Error("API Key not found.");

  let base64Image: string;
  try {
    base64Image = await urlToBase64(originalImageSrc);
  } catch (e: any) {
    throw new Error(`Image processing failed: ${e.message}`);
  }

  const analysis = await analyzeForSuncatcherTheme(base64Image, keyword);
  const userIdeas = ideas.length > 0 ? `Yêu cầu bổ sung: ${ideas.join('. ')}` : '';

  // The master prompt provided by the user
  const masterPrompt = `
Giữ nguyên 100% OUTER FRAME như ảnh gốc (hình tròn, viền/độ dày, inner rim, nét outline đen, chất liệu/texture, micro-scratches, cạnh kính, phản hồi ánh sáng, phối cảnh, tỉ lệ) và giữ nguyên dây treo đúng vị trí (góc, điểm gắn, khoảng cách); tuyệt đối không crop/warp/resize/rotate/move/vẽ lại frame/chain, phải khớp pixel về placement & perspective; CHỈ thiết kế lại toàn bộ phần BÊN TRONG khung theo đúng phong cách stained-glass (lead lines, texture kính, grain/sparkle nhẹ, glow/gradient dịu, saturation/contrast tương tự, phản xạ kính thực, layering đúng: nền sau vật thể) với nền/backplate hoàn toàn mới 100%, giữ logic vùng như bản gốc nhưng vẽ khác toàn bộ; thay toàn bộ vật thể/nhân vật bên trong bằng đối tượng mới ngẫu nhiên nhưng cùng “type/vibe”: ${analysis}, giữ số lượng vật thể chính (±1 nếu cần), giữ vị trí/kích thước/chồng lớp/góc nghiêng tương đối; Nếu ảnh gốc có text thì thay toàn bộ text bên trong bằng text mới ngẫu nhiên giữ vibe font, vị trí, cỡ, độ rõ; bên ngoài khung tạo bối cảnh lifestyle cao cấp thoáng sáng: nội thất tối giản có ánh sáng cửa sổ, bokeh tự nhiên, lá xanh & hoa xuân mờ làm props (không bừa), mặt bàn gỗ sáng bên dưới có phản chiếu mềm của suncatcher; ánh sáng nắng sớm khuếch tán từ sau và hơi trái, có rim/backlight viền khung, highlight ấm, phơi sáng kiểm soát; bố cục hero centered, cùng scale/perspective như input, DOF nông kiểu 85mm f/1.8, nét căng vào suncatcher, nền mờ mạnh nhưng dễ chịu; quy chuẩn chất lượng: mép sắc nét không blur/artifact, lead lines liền mạch đều độ dày, texture kính thật, text rõ ràng; xuất 1 ảnh final độ phân giải cao và xác nhận phần nền/vật thể/text bên trong đã đổi mới trong khi outer frame giữ nguyên.
${userIdeas}
`;

  await wait(1000);
  return generateImage(base64Image, masterPrompt);
};

/**
 * Slot 3: Customization/Edit
 */
export const editImage = async (
  originalImageSrc: string,
  instruction: string
): Promise<string> => {
  if (!ai) throw new Error("API Key not found.");

  let base64Image: string;
  try {
    base64Image = await urlToBase64(originalImageSrc);
  } catch (e: any) {
    throw new Error(`Image processing failed: ${e.message}`);
  }

  const prompt = `
    TASK: Edit the INSIDE content of this suncatcher/ornament.
    INSTRUCTION: "${instruction}"
    CONSTRAINT: 
    - Maintain the outer frame and chain exactly as is.
    - Match the stained-glass art style perfectly.
    - Professional lighting and high resolution.
  `;

  return generateImage(base64Image, prompt);
};

async function generateImage(base64Image: string, prompt: string): Promise<string> {
    if (!ai) throw new Error("API Key missing");

    try {
    const response = await retryWithBackoff<GenerateContentResponse>(() => 
      ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { mimeType: 'image/png', data: base64Image } },
            { text: prompt }
          ]
        }
      })
    );

    if (!response.candidates || response.candidates.length === 0) {
       throw new Error("API blocked by safety or returned no image.");
    }

    const candidate = response.candidates[0];
    if (candidate.finishReason === 'SAFETY') {
        throw new Error("Image blocked by safety filters.");
    }

    const imagePart = candidate.content?.parts?.find(p => p.inlineData);
    if (imagePart && imagePart.inlineData) {
      return `data:${imagePart.inlineData.mimeType || 'image/png'};base64,${imagePart.inlineData.data}`;
    }

    throw new Error("No image data found in response.");
  } catch (error) {
    throw error;
  }
}

import React from 'react';
import { ProductRowData, Idea } from '../types';
import { ImageZone } from './ImageZone';
import { IdeaBlock } from './IdeaBlock';

interface ProductRowProps {
  data: ProductRowData;
  onUpdateRow: (id: string, data: Partial<ProductRowData>) => void;
  onGenerate: (id: string) => void;
  onGenerateConcept: (id: string) => void;
  onImageClick: (rowId: string, type: 'competitor' | 'lifestyle' | 'concept', src: string) => void;
}

export const ProductRow: React.FC<ProductRowProps> = ({ 
  data, 
  onUpdateRow, 
  onGenerate, 
  onGenerateConcept,
  onImageClick
}) => {

  const handleReplaceImage = (file: File, target: 'competitor' | 'lifestyle' | 'concept', index?: number) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const result = e.target?.result as string;
      if (target === 'competitor') {
        onUpdateRow(data.id, { competitorImage: result });
      } else if (target === 'lifestyle') {
         if (typeof index === 'number' && data.redesignedImages) {
             const newImages = [...data.redesignedImages];
             newImages[index] = result;
             onUpdateRow(data.id, { redesignedImages: newImages });
         } else {
             onUpdateRow(data.id, { redesignedImage: result });
         }
      } else if (target === 'concept') {
        onUpdateRow(data.id, { keywordRedesignImage: result });
      }
    };
    reader.readAsDataURL(file);
  };

  const handleDeleteImage = (target: 'competitor' | 'lifestyle' | 'concept', index?: number) => {
    if (target === 'competitor') {
      onUpdateRow(data.id, { competitorImage: '' });
    } else if (target === 'lifestyle') {
      if (typeof index === 'number' && data.redesignedImages) {
         const newImages = data.redesignedImages.filter((_, i) => i !== index);
         onUpdateRow(data.id, { redesignedImages: newImages });
      } else {
         onUpdateRow(data.id, { redesignedImage: '', redesignedImages: [] });
      }
    } else if (target === 'concept') {
      onUpdateRow(data.id, { keywordRedesignImage: '' });
    }
  };

  const addIdea = () => {
    const newIdea: Idea = {
      id: Date.now().toString(),
      text: '',
      isCollapsed: false,
    };
    onUpdateRow(data.id, { ideas: [...data.ideas, newIdea] });
  };

  const updateIdea = (ideaId: string, updates: Partial<Idea>) => {
    const newIdeas = data.ideas.map(idea => 
      idea.id === ideaId ? { ...idea, ...updates } : idea
    );
    onUpdateRow(data.id, { ideas: newIdeas });
  };

  const deleteIdea = (ideaId: string) => {
    const newIdeas = data.ideas.filter(idea => idea.id !== ideaId);
    onUpdateRow(data.id, { ideas: newIdeas });
  };

  const toggleCollapseIdea = (ideaId: string) => {
    const newIdeas = data.ideas.map(idea => 
      idea.id === ideaId ? { ...idea, isCollapsed: !idea.isCollapsed } : idea
    );
    onUpdateRow(data.id, { ideas: newIdeas });
  };

  const lifestyleImages = data.redesignedImages && data.redesignedImages.length > 0 
      ? data.redesignedImages 
      : (data.redesignedImage ? [data.redesignedImage] : []);

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6 mb-6 transition-all hover:shadow-md">
      <div className="mb-6 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <h3 className="text-lg font-semibold text-gray-800">
          <span className="text-gray-400 font-normal mr-2">Product:</span>
          {data.keyword}
        </h3>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">

        {/* Col 1: Original */}
        <div className="flex flex-col space-y-4">
          <div className="flex flex-col space-y-2">
            <div className="text-xs font-medium text-gray-500 uppercase tracking-wide">1. Source Competitor</div>
            <ImageZone 
              src={data.competitorImage} 
              alt={`Original for ${data.keyword}`}
              onReplace={(f) => handleReplaceImage(f, 'competitor')}
              onDelete={() => handleDeleteImage('competitor')}
              onClick={() => onImageClick(data.id, 'competitor', data.competitorImage)}
              isCompetitor
            />
          </div>
        </div>

        {/* Col 2: Master Redesign */}
        <div className="flex flex-col space-y-2">
           <div className="flex items-center justify-between">
              <div className="text-xs font-medium text-blue-600 uppercase tracking-wide">2. Final Concept Redesign</div>
              <button 
                onClick={() => onGenerateConcept(data.id)}
                disabled={data.isGeneratingKeywordRedesign || !data.competitorImage}
                className="text-xs px-2 py-1 bg-blue-50 text-blue-600 hover:bg-blue-100 rounded font-medium disabled:opacity-50"
              >
                {data.isGeneratingKeywordRedesign ? 'Generating...' : '✨ Create Master'}
              </button>
           </div>
           <ImageZone 
            src={data.keywordRedesignImage} 
            alt={`Master Redesign for ${data.keyword}`}
            onReplace={(f) => handleReplaceImage(f, 'concept')}
            onDelete={() => handleDeleteImage('concept')}
            onClick={() => onImageClick(data.id, 'concept', data.keywordRedesignImage || '')}
          />
          <p className="text-xs text-gray-400 italic mt-1">
            Focus: Preserves 100% outer frame. Redesigns entire interior & context.
          </p>
        </div>

        {/* Col 3: Lifestyle Contexts */}
        <div className="flex flex-col space-y-2">
           <div className="flex items-center justify-between">
              <div className="text-xs font-medium text-brand-600 uppercase tracking-wide">
                 3. Lifestyle Contexts {lifestyleImages.length > 0 && `(${lifestyleImages.length})`}
              </div>
              <button 
                onClick={() => onGenerate(data.id)}
                disabled={data.isGenerating || (!data.keywordRedesignImage && !data.competitorImage)}
                className="text-xs px-2 py-1 bg-brand-50 text-brand-600 hover:bg-brand-100 rounded font-medium disabled:opacity-50"
              >
                {data.isGenerating ? 'Wait...' : (data.keywordRedesignImage ? '📸 Generate Settings' : '📸 Context From Original')}
              </button>
           </div>

           {lifestyleImages.length > 0 ? (
             <div className="grid grid-cols-2 gap-2">
                {lifestyleImages.map((imgSrc, idx) => (
                   <div key={idx} className={idx === 0 && lifestyleImages.length % 2 !== 0 ? "col-span-2" : "col-span-1"}>
                       <ImageZone 
                        src={imgSrc} 
                        alt={`Context ${idx + 1}`}
                        onReplace={(f) => handleReplaceImage(f, 'lifestyle', idx)}
                        onDelete={() => handleDeleteImage('lifestyle', idx)}
                        onClick={() => onImageClick(data.id, 'lifestyle', imgSrc)}
                      />
                   </div>
                ))}
             </div>
           ) : (
             <ImageZone 
                src={undefined} 
                alt="No Lifestyle Mockups"
                onReplace={(f) => handleReplaceImage(f, 'lifestyle')}
                onDelete={() => handleDeleteImage('lifestyle')}
              />
           )}

          <p className="text-xs text-gray-400 italic mt-1">
            Focus: Places existing design into premium interior environments.
          </p>
        </div>

        {/* Col 4: Directives */}
        <div className="flex flex-col h-full">
           <div className="flex items-center justify-between mb-2">
             <div className="text-xs font-medium text-gray-500 uppercase tracking-wide">4. Custom Directives</div>
             <button 
               onClick={addIdea}
               className="p-1 rounded bg-gray-100 hover:bg-gray-200 text-gray-600 transition-colors"
               title="Add Instruction"
             >
               <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
             </button>
           </div>

           <div className="flex-1 overflow-y-auto max-h-[600px] pr-1 space-y-2">
             {data.ideas.length === 0 && (
               <div className="text-sm text-gray-400 italic p-4 text-center border-2 border-dashed border-gray-100 rounded-lg">
                 Add prompts to tweak the AI.
               </div>
             )}
             {data.ideas.map(idea => (
               <IdeaBlock 
                 key={idea.id}
                 idea={idea}
                 onUpdate={updateIdea}
                 onDelete={deleteIdea}
                 onToggleCollapse={toggleCollapseIdea}
               />
             ))}
           </div>
        </div>

      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { ProductRowData } from './types';
import { fetchSheetData } from './services/sheetService';
import { generateRedesign, generateProductConcept, editImage } from './services/geminiService';
import { ProductRow } from './components/ProductRow';
import { ImageModal } from './components/ImageModal';

export default function App() {
  const [sheetUrl, setSheetUrl] = useState('https://docs.google.com/spreadsheets/d/1Z6oK-BNw8qDNBO9fQ28XOD3eTJzQwdPL6HCePR9uC0U/edit?gid=224107427#gid=224107427');
  const [data, setData] = useState<ProductRowData[]>([]);
  const [isLoadingData, setIsLoadingData] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Modal State
  const [modalOpen, setModalOpen] = useState(false);
  const [selectedImage, setSelectedImage] = useState<{
    rowId: string;
    type: 'competitor' | 'lifestyle' | 'concept';
    src: string;
    keyword: string;
  } | null>(null);

  const handleGetData = async () => {
    if (!sheetUrl) return;
    setIsLoadingData(true);
    setError(null);
    try {
      const fetchedData = await fetchSheetData(sheetUrl);
      setData(fetchedData);
    } catch (err) {
      setError("Failed to fetch data. Please check the URL.");
    } finally {
      setIsLoadingData(false);
    }
  };

  const updateRow = (id: string, updates: Partial<ProductRowData>) => {
    setData(prev => prev.map(row => (row.id === id ? { ...row, ...updates } : row)));
  };

  const handleGenerate = async (id: string) => {
    const row = data.find(r => r.id === id);
    if (!row) return;

    const sourceImage = row.keywordRedesignImage || row.competitorImage;

    if (!sourceImage) {
      alert("Please generate a Concept Redesign first, or ensure a Competitor image exists.");
      return;
    }

    updateRow(id, { isGenerating: true, redesignedImages: [] });

    try {
      const generatedImages = await generateRedesign(
        row.keyword, 
        sourceImage
      );

      updateRow(id, { 
        isGenerating: false, 
        redesignedImages: generatedImages 
      });
    } catch (e: any) {
      console.error(e);
      updateRow(id, { isGenerating: false });
      alert(e.message);
    }
  };

  const handleGenerateConcept = async (id: string) => {
    const row = data.find(r => r.id === id);
    if (!row || !row.competitorImage) return;

    updateRow(id, { isGeneratingKeywordRedesign: true, keywordRedesignImage: undefined });

    try {
      const ideasText = row.ideas.map(i => i.text).filter(Boolean);

      const generatedImageBase64 = await generateProductConcept(
        row.keyword, 
        row.competitorImage, 
        ideasText
      );

      updateRow(id, { 
        isGeneratingKeywordRedesign: false, 
        keywordRedesignImage: generatedImageBase64 
      });
    } catch (e: any) {
      console.error(e);
      updateRow(id, { isGeneratingKeywordRedesign: false });
      alert(e.message);
    }
  };

  const handleImageClick = (rowId: string, type: 'competitor' | 'lifestyle' | 'concept', src: string) => {
    const row = data.find(r => r.id === rowId);
    if (row && src) {
      setSelectedImage({
        rowId,
        type,
        src,
        keyword: row.keyword
      });
      setModalOpen(true);
    }
  };

  const handleModalGenerate = async (type: 'customize' | 'redesign', instruction?: string): Promise<string> => {
    if (!selectedImage) throw new Error("No image selected");

    if (type === 'customize') {
      return await editImage(selectedImage.src, instruction || "Enhance this design");
    } 

    return await generateProductConcept(
      selectedImage.keyword,
      selectedImage.src,
      instruction ? [instruction] : []
    );
  };

  const handleModalSave = (newImageSrc: string) => {
    if (!selectedImage) return;

    const row = data.find(r => r.id === selectedImage.rowId);
    if (!row) return;

    let targetField: Partial<ProductRowData> = {};

    if (selectedImage.type === 'competitor' || selectedImage.type === 'concept') {
      targetField = { keywordRedesignImage: newImageSrc };
    } else if (selectedImage.type === 'lifestyle') {
       const currentImages = row.redesignedImages || [];
       targetField = { redesignedImages: [...currentImages, newImageSrc] };
    }

    updateRow(selectedImage.rowId, targetField);
    setModalOpen(false);
  };

  return (
    <div className="min-h-screen bg-slate-50 text-gray-800 font-sans pb-20">

      <header className="bg-white border-b border-gray-200 sticky top-0 z-50">
        <div className="max-w-[1400px] mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold text-lg">S</div>
            <h1 className="text-xl font-semibold tracking-tight">Suncatcher Design Workspace</h1>
          </div>
          <div className="text-sm text-gray-500 hidden sm:block">
            Gemini-Powered Visual Mastermind
          </div>
        </div>
