import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const apiKey = process.env.API_KEY || '';

// Initialize only if key exists to avoid immediate errors, though usage will check
const ai = apiKey ? new GoogleGenAI({ apiKey }) : null;

const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

/**
 * Helper function to retry async operations with exponential backoff.
 * Handles 429 (Rate Limit) and 503 (Overloaded).
 */
async function retryWithBackoff<T>(
  fn: () => Promise<T>,
  retries = 3,
  delay = 2000
): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const isRateLimit = 
      error.status === 429 || 
      error.code === 429 || 
      (error.message && typeof error.message === 'string' && error.message.includes("RESOURCE_EXHAUSTED"));

    const isOverloaded =
      error.status === 503 ||
      error.code === 503 ||
      (error.message && typeof error.message === 'string' && error.message.toLowerCase().includes("overloaded"));

    if (retries > 0 && (isRateLimit || isOverloaded)) {
      const nextDelay = isRateLimit ? Math.max(delay, 4000) : delay;
      console.warn(`API ${isRateLimit ? 'Rate Limit' : 'Overloaded'}. Retrying in ${nextDelay}ms... (${retries} attempts left)`);

      await wait(nextDelay);
      return retryWithBackoff(fn, retries - 1, nextDelay * 2);
    }
    throw error;
  }
}

/**
 * Converts a base64 string or URL to a format suitable for the API.
 */
async function urlToBase64(url: string): Promise<string> {
  if (url.startsWith('data:')) {
    return url.split(',')[1];
  }

  const fetchBlob = async (targetUrl: string): Promise<Blob> => {
    const response = await fetch(targetUrl);
    if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
    return await response.blob();
  };

  const strategies = [
    { name: 'Direct', getUrl: (u: string) => u },
    { name: 'Weserv', getUrl: (u: string) => `https://images.weserv.nl/?url=${encodeURIComponent(u)}&output=png&il` },
    { name: 'CorsProxy', getUrl: (u: string) => `https://corsproxy.io/?${encodeURIComponent(u)}` },
    { name: 'AllOrigins', getUrl: (u: string) => `https://api.allorigins.win/raw?url=${encodeURIComponent(u)}` }
  ];

  for (const strategy of strategies) {
    try {
      const blob = await fetchBlob(strategy.getUrl(url));
      return await new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onloadend = () => {
          const result = reader.result as string;
          resolve(result.split(',')[1]);
        };
        reader.onerror = reject;
        reader.readAsDataURL(blob);
      });
    } catch (e) {
      console.warn(`Fetch strategy '${strategy.name}' failed for ${url}`, e);
    }
  }

  throw new Error("Could not download image. Please upload it directly.");
}

/**
 * Analyzes for Ornament strategy before generation.
 */
async function analyzeForOrnamentTheme(base64Image: string, keyword: string): Promise<string> {
  if (!ai) throw new Error("API Key not found.");

  const analysisPrompt = `
    Analyze this acrylic ornament image and the keyword "${keyword}".
    Identify:
    1. The core theme/subject inside the frame.
    2. The style of the illustration (e.g., flat, watercolor, cartoon).
    3. The color palette.

    Return a brief description of a FRESH, NEW variation of this subject that would fit perfectly inside the exact same frame.
    Keep the "vibe" but change the specific details (e.g., if it's a cat, describe a different breed or pose).
    Ensure the description is suitable for a 2D flat acrylic print (no stained glass effects).
  `;

  try {
    const response = await retryWithBackoff<GenerateContentResponse>(() => 
      ai.models.generateContent({
        model: 'gemini-3-flash-preview', 
        contents: {
          parts: [
            { inlineData: { mimeType: 'image/png', data: base64Image } },
            { text: analysisPrompt }
          ]
        }
      })
    );
    return response.text || `A beautiful 2D acrylic ornament variation of ${keyword}.`;
  } catch (error) {
    return `A premium 2D acrylic ornament design for ${keyword}.`;
  }
}

/**
 * Slot 1: Lifestyle Mockup (Generates 3 distinct high-end variations)
 */
export const generateRedesign = async (
  keyword: string, 
  originalImageSrc: string,
  ideas: string[] = []
): Promise<string[]> => {
  if (!ai) throw new Error("API Key not found.");

  let base64Image: string;
  try {
    base64Image = await urlToBase64(originalImageSrc);
  } catch (e: any) {
    throw new Error(`Image processing failed: ${e.message}`);
  }

  const contexts = [
    "Modern minimalist sunlit living room with large windows.",
    "Cozy reading nook with warm morning light and plants.",
    "Professional studio photography with soft bokeh and spring flowers."
  ];

  const successfulImages: string[] = [];

  for (const context of contexts) {
    const prompt = `
      Create a high-end lifestyle mockup of the provided acrylic ornament.
      SCENE: ${context}
      CONSTRAINTS:
      - Keep the ornament frame and shape 100% identical to the input.
      - Place it hanging in front of a window or over a light wood table.
      - Use shallow depth of field (85mm f/1.8), sharp focus on the ornament.
      - Diffused morning sunlight from back-left with soft reflections.
      - Professional aesthetic, crisp details.
      - Material: Clear acrylic with printed 2D design (flat/semi-flat), NOT stained glass.
    `;

    try {
        if (successfulImages.length > 0) await wait(2000);
        const img = await generateImage(base64Image, prompt);
        successfulImages.push(img);
    } catch (err) {
        console.error("Failed variation:", err);
    }
  }

  if (successfulImages.length === 0) throw new Error("Generation failed.");
  return successfulImages;
};

