/**
 * Slot 3: Customization/Edit
 */
export const editImage = async (
  originalImageSrc: string,
  instruction: string
): Promise<string> => {
  if (!ai) throw new Error("API Key not found.");

  let base64Image: string;
  try {
    base64Image = await urlToBase64(originalImageSrc);
  } catch (e: any) {
    throw new Error(`Image processing failed: ${e.message}`);
  }

  const prompt = `
    TASK: Edit the INSIDE content of this Acrylic Ornament (2D flat print on acrylic).
    INSTRUCTION: "${instruction}"
    CONSTRAINT: 
    - Maintain the outer frame and chain exactly as is.
    - Match the 2D Acrylic Ornament art style (flat/semi-flat print, no stained glass).
    - Professional lighting and high resolution.
  `;

  return generateImage(base64Image, prompt);
};

async function generateImage(base64Image: string, prompt: string): Promise<string> {
    if (!ai) throw new Error("API Key missing");

    try {
    const response = await retryWithBackoff<GenerateContentResponse>(() => 
      ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { mimeType: 'image/png', data: base64Image } },
            { text: prompt }
          ]
        }
      })
    );

    if (!response.candidates || response.candidates.length === 0) {
       throw new Error("API blocked by safety or returned no image.");
    }

    const candidate = response.candidates[0];
    if (candidate.finishReason === 'SAFETY') {
        throw new Error("Image blocked by safety filters.");
    }

    const imagePart = candidate.content?.parts?.find(p => p.inlineData);
    if (imagePart && imagePart.inlineData) {
      return `data:${imagePart.inlineData.mimeType || 'image/png'};base64,${imagePart.inlineData.data}`;
    }

    throw new Error("No image data found in response.");
  } catch (error) {
    throw error;
  }
}

import React, { useState } from 'react';
import { ProductRowData } from './types';
import { fetchSheetData } from './services/sheetService';
import { generateRedesign, generateProductConcept, editImage } from './services/geminiService';
import { ProductRow } from './components/ProductRow';
import { ImageModal } from './components/ImageModal';

export default function App() {
  const [sheetUrl, setSheetUrl] = useState('https://docs.google.com/spreadsheets/d/1Z6oK-BNw8qDNBO9fQ28XOD3eTJzQwdPL6HCePR9uC0U/edit?gid=224107427#gid=224107427');
  const [data, setData] = useState<ProductRowData[]>([]);
  const [isLoadingData, setIsLoadingData] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Modal State
  const [modalOpen, setModalOpen] = useState(false);
  const [selectedImage, setSelectedImage] = useState<{
    rowId: string;
    type: 'competitor' | 'lifestyle' | 'concept';
    src: string;
    keyword: string;
  } | null>(null);

  const handleGetData = async () => {
    if (!sheetUrl) return;
    setIsLoadingData(true);
    setError(null);
    try {
      const fetchedData = await fetchSheetData(sheetUrl);
      setData(fetchedData);
    } catch (err) {
      setError("Failed to fetch data. Please check the URL.");
    } finally {
      setIsLoadingData(false);
    }
  };

  const updateRow = (id: string, updates: Partial<ProductRowData>) => {
    setData(prev => prev.map(row => (row.id === id ? { ...row, ...updates } : row)));
  };

  const handleGenerate = async (id: string) => {
    const row = data.find(r => r.id === id);
    if (!row) return;

    const sourceImage = row.keywordRedesignImage || row.competitorImage;

    if (!sourceImage) {
      alert("Please generate a Concept Redesign first, or ensure a Competitor image exists.");
      return;
    }

    updateRow(id, { isGenerating: true, redesignedImages: [] });

    try {
      const generatedImages = await generateRedesign(
        row.keyword, 
        sourceImage
      );

      updateRow(id, { 
        isGenerating: false, 
        redesignedImages: generatedImages 
      });
    } catch (e: any) {
      console.error(e);
      updateRow(id, { isGenerating: false });
      alert(e.message);
    }
  };

  const handleGenerateConcept = async (id: string) => {
    const row = data.find(r => r.id === id);
    if (!row || !row.competitorImage) return;

    updateRow(id, { isGeneratingKeywordRedesign: true, keywordRedesignImage: undefined });

    try {
      const ideasText = row.ideas.map(i => i.text).filter(Boolean);

      const generatedImageBase64 = await generateProductConcept(
        row.keyword, 
        row.competitorImage, 
        ideasText
      );

      updateRow(id, { 
        isGeneratingKeywordRedesign: false, 
        keywordRedesignImage: generatedImageBase64 
      });
    } catch (e: any) {
      console.error(e);
      updateRow(id, { isGeneratingKeywordRedesign: false });
      alert(e.message);
    }
