import React from 'react';
import { ProductRowData, Idea } from '../types';
import { ImageZone } from './ImageZone';
import { IdeaBlock } from './IdeaBlock';

interface ProductRowProps {
  data: ProductRowData;
  onUpdateRow: (id: string, data: Partial<ProductRowData>) => void;
  onGenerate: (id: string) => void;
  onGenerateConcept: (id: string) => void;
  onImageClick: (rowId: string, type: 'competitor' | 'lifestyle' | 'concept', src: string) => void;
}

export const ProductRow: React.FC<ProductRowProps> = ({ 
  data, 
  onUpdateRow, 
  onGenerate, 
  onGenerateConcept,
  onImageClick
}) => {

  const handleReplaceImage = (file: File, target: 'competitor' | 'lifestyle' | 'concept', index?: number) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const result = e.target?.result as string;
      if (target === 'competitor') {
        onUpdateRow(data.id, { competitorImage: result });
      } else if (target === 'lifestyle') {
         if (typeof index === 'number' && data.redesignedImages) {
             const newImages = [...data.redesignedImages];
             newImages[index] = result;
             onUpdateRow(data.id, { redesignedImages: newImages });
         } else {
             onUpdateRow(data.id, { redesignedImage: result });
         }
      } else if (target === 'concept') {
        onUpdateRow(data.id, { keywordRedesignImage: result });
      }
    };
    reader.readAsDataURL(file);
  };

  const handleDeleteImage = (target: 'competitor' | 'lifestyle' | 'concept', index?: number) => {
    if (target === 'competitor') {
      onUpdateRow(data.id, { competitorImage: '' });
    } else if (target === 'lifestyle') {
      if (typeof index === 'number' && data.redesignedImages) {
         const newImages = data.redesignedImages.filter((_, i) => i !== index);
         onUpdateRow(data.id, { redesignedImages: newImages });
      } else {
         onUpdateRow(data.id, { redesignedImage: '', redesignedImages: [] });
      }
    } else if (target === 'concept') {
      onUpdateRow(data.id, { keywordRedesignImage: '' });
    }
  };

  const addIdea = () => {
    const newIdea: Idea = {
      id: Date.now().toString(),
      text: '',
      isCollapsed: false,
    };
    onUpdateRow(data.id, { ideas: [...data.ideas, newIdea] });
  };

  const updateIdea = (ideaId: string, updates: Partial<Idea>) => {
    const newIdeas = data.ideas.map(idea => 
      idea.id === ideaId ? { ...idea, ...updates } : idea
    );
    onUpdateRow(data.id, { ideas: newIdeas });
  };

  const deleteIdea = (ideaId: string) => {
    const newIdeas = data.ideas.filter(idea => idea.id !== ideaId);
    onUpdateRow(data.id, { ideas: newIdeas });
  };

  const toggleCollapseIdea = (ideaId: string) => {
    const newIdeas = data.ideas.map(idea => 
      idea.id === ideaId ? { ...idea, isCollapsed: !idea.isCollapsed } : idea
    );
    onUpdateRow(data.id, { ideas: newIdeas });
  };

  const lifestyleImages = data.redesignedImages && data.redesignedImages.length > 0 
      ? data.redesignedImages 
      : (data.redesignedImage ? [data.redesignedImage] : []);

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6 mb-6 transition-all hover:shadow-md">
      <div className="mb-6 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <h3 className="text-lg font-semibold text-gray-800">
          <span className="text-gray-400 font-normal mr-2">Product:</span>
          {data.keyword}
        </h3>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">

        {/* Col 1: Original */}
        <div className="flex flex-col space-y-4">
          <div className="flex flex-col space-y-2">
            <div className="text-xs font-medium text-gray-500 uppercase tracking-wide">1. Source Competitor</div>
            <ImageZone 
              src={data.competitorImage} 
              alt={`Original for ${data.keyword}`}
              onReplace={(f) => handleReplaceImage(f, 'competitor')}
              onDelete={() => handleDeleteImage('competitor')}
              onClick={() => onImageClick(data.id, 'competitor', data.competitorImage)}
              isCompetitor
            />
          </div>
        </div>

        {/* Col 2: Master Redesign */}
        <div className="flex flex-col space-y-2">
           <div className="flex items-center justify-between">
              <div className="text-xs font-medium text-blue-600 uppercase tracking-wide">2. Final Concept Redesign</div>
              <button 
                onClick={() => onGenerateConcept(data.id)}
                disabled={data.isGeneratingKeywordRedesign || !data.competitorImage}
                className="text-xs px-2 py-1 bg-blue-50 text-blue-600 hover:bg-blue-100 rounded font-medium disabled:opacity-50"
              >
                {data.isGeneratingKeywordRedesign ? 'Generating...' : '✨ Create Master'}
              </button>
           </div>
           <ImageZone 
            src={data.keywordRedesignImage} 
            alt={`Master Redesign for ${data.keyword}`}
            onReplace={(f) => handleReplaceImage(f, 'concept')}
            onDelete={() => handleDeleteImage('concept')}
            onClick={() => onImageClick(data.id, 'concept', data.keywordRedesignImage || '')}
          />
          <p className="text-xs text-gray-400 italic mt-1">
            Focus: Preserves 100% outer frame. Redesigns entire interior & context (Acrylic 2D).
          </p>
        </div>

        {/* Col 3: Lifestyle Contexts */}
        <div className="flex flex-col space-y-2">
           <div className="flex items-center justify-between">
              <div className="text-xs font-medium text-brand-600 uppercase tracking-wide">
                 3. Lifestyle Contexts {lifestyleImages.length > 0 && `(${lifestyleImages.length})`}
              </div>
              <button 
                onClick={() => onGenerate(data.id)}
                disabled={data.isGenerating || (!data.keywordRedesignImage && !data.competitorImage)}
                className="text-xs px-2 py-1 bg-brand-50 text-brand-600 hover:bg-brand-100 rounded font-medium disabled:opacity-50"
              >
                {data.isGenerating ? 'Wait...' : (data.keywordRedesignImage ? '📸 Generate Settings' : '📸 Context From Original')}
              </button>
           </div>

           {lifestyleImages.length > 0 ? (
             <div className="grid grid-cols-2 gap-2">
                {lifestyleImages.map((imgSrc, idx) => (
                   <div key={idx} className={idx === 0 && lifestyleImages.length % 2 !== 0 ? "col-span-2" : "col-span-1"}>
                       <ImageZone 
                        src={imgSrc} 
                        alt={`Context ${idx + 1}`}
                        onReplace={(f) => handleReplaceImage(f, 'lifestyle', idx)}
                        onDelete={() => handleDeleteImage('lifestyle', idx)}
                        onClick={() => onImageClick(data.id, 'lifestyle', imgSrc)}
                      />
                   </div>
                ))}
             </div>
           ) : (
             <ImageZone 
                src={undefined} 
                alt="No Lifestyle Mockups"
                onReplace={(f) => handleReplaceImage(f, 'lifestyle')}
                onDelete={() => handleDeleteImage('lifestyle')}
              />
           )}

          <p className="text-xs text-gray-400 italic mt-1">
            Focus: Places existing design into premium interior environments.
          </p>
        </div>

        {/* Col 4: Directives */}
        <div className="flex flex-col h-full">
           <div className="flex items-center justify-between mb-2">
             <div className="text-xs font-medium text-gray-500 uppercase tracking-wide">4. Custom Directives</div>
             <button 
               onClick={addIdea}
               className="p-1 rounded bg-gray-100 hover:bg-gray-200 text-gray-600 transition-colors"
               title="Add Instruction"
             >
               <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
             </button>
           </div>

           <div className="flex-1 overflow-y-auto max-h-[600px] pr-1 space-y-2">
             {data.ideas.length === 0 && (
               <div className="text-sm text-gray-400 italic p-4 text-center border-2 border-dashed border-gray-100 rounded-lg">
                 Add prompts to tweak the AI.
               </div>
             )}
             {data.ideas.map(idea => (
               <IdeaBlock 
                 key={idea.id}
                 idea={idea}
                 onUpdate={updateIdea}
                 onDelete={deleteIdea}
                 onToggleCollapse={toggleCollapseIdea}
               />
             ))}
           </div>
        </div>

      </div>
    </div>
  );
};

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const apiKey = process.env.API_KEY || '';

// Initialize only if key exists to avoid immediate errors, though usage will check
const ai = apiKey ? new GoogleGenAI({ apiKey }) : null;

const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

/**
 * Helper function to retry async operations with exponential backoff.
 * Handles 429 (Rate Limit) and 503 (Overloaded).
 */
async function retryWithBackoff<T>(
  fn: () => Promise<T>,
  retries = 3,
  delay = 2000
): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const isRateLimit = 
      error.status === 429 || 
      error.code === 429 || 
      (error.message && typeof error.message === 'string' && error.message.includes("RESOURCE_EXHAUSTED"));

    const isOverloaded =
      error.status === 503 ||
      error.code === 503 ||
      (error.message && typeof error.message === 'string' && error.message.toLowerCase().includes("overloaded"));

    if (retries > 0 && (isRateLimit || isOverloaded)) {
      const nextDelay = isRateLimit ? Math.max(delay, 4000) : delay;
      console.warn(`API ${isRateLimit ? 'Rate Limit' : 'Overloaded'}. Retrying in ${nextDelay}ms... (${retries} attempts left)`);

      await wait(nextDelay);
      return retryWithBackoff(fn, retries - 1, nextDelay * 2);
    }
    throw error;
  }
}

/**
 * Converts a base64 string or URL to a format suitable for the API.
 */
async function urlToBase64(url: string): Promise<string> {
  if (url.startsWith('data:')) {
    return url.split(',')[1];
  }

  const fetchBlob = async (targetUrl: string): Promise<Blob> => {
    const response = await fetch(targetUrl);
    if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
    return await response.blob();
  };

  const strategies = [
    { name: 'Direct', getUrl: (u: string) => u },
    { name: 'Weserv', getUrl: (u: string) => `https://images.weserv.nl/?url=${encodeURIComponent(u)}&output=png&il` },
    { name: 'CorsProxy', getUrl: (u: string) => `https://corsproxy.io/?${encodeURIComponent(u)}` },
    { name: 'AllOrigins', getUrl: (u: string) => `https://api.allorigins.win/raw?url=${encodeURIComponent(u)}` }
  ];

  for (const strategy of strategies) {
    try {
      const blob = await fetchBlob(strategy.getUrl(url));
      return await new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onloadend = () => {
          const result = reader.result as string;
          resolve(result.split(',')[1]);
        };
        reader.onerror = reject;
        reader.readAsDataURL(blob);
      });
    } catch (e) {
      console.warn(`Fetch strategy '${strategy.name}' failed for ${url}`, e);
    }
  }

  throw new Error("Could not download image. Please upload it directly.");
}

/**
 * Analyzes for Ornament strategy before generation.
 */
async function analyzeForOrnamentTheme(base64Image: string, keyword: string): Promise<string> {
  if (!ai) throw new Error("API Key not found.");

  const analysisPrompt = `
    Analyze this acrylic ornament image and the keyword "${keyword}".
    Identify:
    1. The core theme/subject inside the frame.
    2. The style of the illustration (e.g., flat, watercolor, cartoon).
    3. The color palette.

    Return a brief description of a FRESH, NEW variation of this subject that would fit perfectly inside the exact same frame.
    Keep the "vibe" but change the specific details (e.g., if it's a cat, describe a different breed or pose).
    Ensure the description is suitable for a 2D flat acrylic print (no stained glass effects).
  `;

  try {
    const response = await retryWithBackoff<GenerateContentResponse>(() => 
      ai.models.generateContent({
        model: 'gemini-3-flash-preview', 
        contents: {
          parts: [
            { inlineData: { mimeType: 'image/png', data: base64Image } },
            { text: analysisPrompt }
          ]
        }
      })
    );
    return response.text || `A beautiful 2D acrylic ornament variation of ${keyword}.`;
  } catch (error) {
    return `A premium 2D acrylic ornament design for ${keyword}.`;
  }
}

