export const editImage = async (
  originalImageSrc: string,
  instruction: string
): Promise<string> => {
  if (!ai) throw new Error("API Key not found.");

  let base64Image: string;
  try {
    base64Image = await urlToBase64(originalImageSrc);
  } catch (e: any) {
    throw new Error(`Image processing failed: ${e.message}`);
  }

  const prompt = `
    TASK: Edit the INSIDE content of this Stained Glass Ornament.
    INSTRUCTION: "${instruction}"
    CONSTRAINT: 
    - Maintain the outer frame and chain exactly as is.
    - Match the Stained Glass art style (lead lines, glass texture).
    - Professional lighting and high resolution.
  `;

  return generateImage(base64Image, prompt);
