  const [error, setError] = useState<string | null>(null);

  // Modal State
  const [modalOpen, setModalOpen] = useState(false);
  const [selectedImage, setSelectedImage] = useState<{
    rowId: string;
    type: 'competitor' | 'lifestyle' | 'concept';
    src: string;
    keyword: string;
  } | null>(null);

  const handleGetData = async () => {
    if (!sheetUrl) return;
    setIsLoadingData(true);
    setError(null);
    try {
      const fetchedData = await fetchSheetData(sheetUrl);
      setData(fetchedData);
    } catch (err) {
      setError("Failed to fetch data. Please check the URL.");
    } finally {
      setIsLoadingData(false);
    }
  };

  const updateRow = (id: string, updates: Partial<ProductRowData>) => {
    setData(prev => prev.map(row => (row.id === id ? { ...row, ...updates } : row)));
  };

  const handleGenerate = async (id: string) => {
    const row = data.find(r => r.id === id);
    if (!row) return;

    const sourceImage = row.keywordRedesignImage || row.competitorImage;

    if (!sourceImage) {
      alert("Please generate a Concept Redesign first, or ensure a Competitor image exists.");
      return;
    }

    updateRow(id, { isGenerating: true, redesignedImages: [] });

    try {
      const generatedImages = await generateRedesign(
        row.keyword, 
        sourceImage
      );

      updateRow(id, { 
        isGenerating: false, 
        redesignedImages: generatedImages 
      });
    } catch (e: any) {
      console.error(e);
      updateRow(id, { isGenerating: false });
      alert(e.message);
    }
  };

  const handleGenerateConcept = async (id: string) => {
    const row = data.find(r => r.id === id);
    if (!row || !row.competitorImage) return;

    updateRow(id, { isGeneratingKeywordRedesign: true, keywordRedesignImage: undefined });

    try {
      // We pass ideas but they are currently ignored by the new prompt logic as per request,
      // but keeping signature for compatibility.
      const ideasText = row.ideas.map(i => i.text).filter(Boolean);

      const generatedImageBase64 = await generateProductConcept(
        row.keyword, 
        row.competitorImage, 
        ideasText
      );

      updateRow(id, { 
        isGeneratingKeywordRedesign: false, 
        keywordRedesignImage: generatedImageBase64 
      });
    } catch (e: any) {
      console.error(e);
      updateRow(id, { isGeneratingKeywordRedesign: false });
      alert(e.message);
    }
  };

  const handleImageClick = (rowId: string, type: 'competitor' | 'lifestyle' | 'concept', src: string) => {
    const row = data.find(r => r.id === rowId);
    if (row && src) {
      setSelectedImage({
        rowId,
        type,
        src,
        keyword: row.keyword
      });
      setModalOpen(true);
    }
  };

  const handleModalGenerate = async (type: 'customize' | 'redesign', instruction?: string): Promise<string> => {
    if (!selectedImage) throw new Error("No image selected");

    if (type === 'customize') {
      return await editImage(selectedImage.src, instruction || "Enhance this design");
    } 

    return await generateProductConcept(
      selectedImage.keyword,
      selectedImage.src,
      instruction ? [instruction] : []
    );
  };

  const handleModalSave = (newImageSrc: string) => {
    if (!selectedImage) return;

    const row = data.find(r => r.id === selectedImage.rowId);
    if (!row) return;

    let targetField: Partial<ProductRowData> = {};

    if (selectedImage.type === 'competitor' || selectedImage.type === 'concept') {
      targetField = { keywordRedesignImage: newImageSrc };
    } else if (selectedImage.type === 'lifestyle') {
       const currentImages = row.redesignedImages || [];
       targetField = { redesignedImages: [...currentImages, newImageSrc] };
    }

    updateRow(selectedImage.rowId, targetField);
    setModalOpen(false);
  };

  return (
    <div className="min-h-screen bg-slate-50 text-gray-800 font-sans pb-20">

      <header className="bg-white border-b border-gray-200 sticky top-0 z-50">
        <div className="max-w-[1400px] mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold text-lg">A</div>
            <h1 className="text-xl font-semibold tracking-tight">Acrylic Ornament Design Workspace</h1>
          </div>
          <div className="text-sm text-gray-500 hidden sm:block">
            Gemini-Powered Visual Mastermind
          </div>
        </div>
      </header>

      <main className="max-w-[1400px] mx-auto px-4 sm:px-6 lg:px-8 py-8">

        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-8 mb-8 text-center">
           <h2 className="text-2xl font-bold mb-2">Import Spreadsheet Data</h2>
           <p className="text-gray-500 mb-6">Load product keywords and competitor images to start the redesign process.</p>

           <div className="max-w-2xl mx-auto flex flex-col sm:flex-row gap-3">
             <input 
               type="text" 
               placeholder="Google Sheets URL..." 
               className="flex-1 px-4 py-3 rounded-xl border border-gray-200 focus:border-indigo-500 focus:ring-2 focus:ring-indigo-200 outline-none transition-all"
               value={sheetUrl}
               onChange={(e) => setSheetUrl(e.target.value)}
