             <button 
               onClick={handleGetData}
               disabled={isLoadingData}
               className="px-8 py-3 bg-indigo-900 text-white rounded-xl font-medium hover:bg-indigo-800 transition-all shadow-lg shadow-indigo-200 disabled:opacity-50 disabled:cursor-not-allowed"
             >
               {isLoadingData ? 'Loading...' : 'Get Dữ Liệu'}
