async function generateImage(base64Image: string, prompt: string): Promise<string> {
    if (!ai) throw new Error("API Key missing");

    try {
    const response = await retryWithBackoff<GenerateContentResponse>(() => 
      ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { mimeType: 'image/png', data: base64Image } },
            { text: prompt }
          ]
        }
      })
    );

    if (!response.candidates || response.candidates.length === 0) {
       throw new Error("API blocked by safety or returned no image.");
    }

    const candidate = response.candidates[0];
    if (candidate.finishReason === 'SAFETY') {
        throw new Error("Image blocked by safety filters.");
    }

    const imagePart = candidate.content?.parts?.find(p => p.inlineData);
    if (imagePart && imagePart.inlineData) {
      return `data:${imagePart.inlineData.mimeType || 'image/png'};base64,${imagePart.inlineData.data}`;
    }

    throw new Error("No image data found in response.");
  } catch (error) {
    throw error;
  }
}

import React from 'react';
import { ProductRowData } from '../types';
import { ImageZone } from './ImageZone';

interface ProductRowProps {
  data: ProductRowData;
  onUpdateRow: (id: string, data: Partial<ProductRowData>) => void;
  onGenerate: (id: string) => void;
  onGenerateConcept: (id: string) => void;
  onImageClick: (rowId: string, type: 'competitor' | 'lifestyle' | 'concept', src: string) => void;
}

export const ProductRow: React.FC<ProductRowProps> = ({ 
  data, 
  onUpdateRow, 
  onGenerate, 
  onGenerateConcept,
  onImageClick
}) => {

  const handleReplaceImage = (file: File, target: 'competitor' | 'lifestyle' | 'concept', index?: number) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const result = e.target?.result as string;
      if (target === 'competitor') {
        onUpdateRow(data.id, { competitorImage: result });
      } else if (target === 'lifestyle') {
         if (typeof index === 'number' && data.redesignedImages) {
             const newImages = [...data.redesignedImages];
             newImages[index] = result;
             onUpdateRow(data.id, { redesignedImages: newImages });
         } else {
             onUpdateRow(data.id, { redesignedImage: result });
         }
      } else if (target === 'concept') {
        onUpdateRow(data.id, { keywordRedesignImage: result });
      }
    };
    reader.readAsDataURL(file);
  };

  const handleDeleteImage = (target: 'competitor' | 'lifestyle' | 'concept', index?: number) => {
    if (target === 'competitor') {
      onUpdateRow(data.id, { competitorImage: '' });
    } else if (target === 'lifestyle') {
      if (typeof index === 'number' && data.redesignedImages) {
         const newImages = data.redesignedImages.filter((_, i) => i !== index);
         onUpdateRow(data.id, { redesignedImages: newImages });
      } else {
         onUpdateRow(data.id, { redesignedImage: '', redesignedImages: [] });
      }
    } else if (target === 'concept') {
      onUpdateRow(data.id, { keywordRedesignImage: '' });
    }
  };

  const lifestyleImages = data.redesignedImages && data.redesignedImages.length > 0 
      ? data.redesignedImages 
      : (data.redesignedImage ? [data.redesignedImage] : []);

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6 mb-6 transition-all hover:shadow-md">
      <div className="mb-6 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <h3 className="text-lg font-semibold text-gray-800">
          <span className="text-gray-400 font-normal mr-2">Product:</span>
          {data.keyword}
        </h3>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">

        {/* Col 1: Original */}
        <div className="flex flex-col space-y-4">
          <div className="flex flex-col space-y-2">
            <div className="text-xs font-medium text-gray-500 uppercase tracking-wide">1. Source Competitor</div>
            <ImageZone 
              src={data.competitorImage} 
              alt={`Original for ${data.keyword}`}
              onReplace={(f) => handleReplaceImage(f, 'competitor')}
              onDelete={() => handleDeleteImage('competitor')}
              onClick={() => onImageClick(data.id, 'competitor', data.competitorImage)}
              isCompetitor
            />
          </div>
        </div>

        {/* Col 2: Master Redesign */}
        <div className="flex flex-col space-y-2">
           <div className="flex items-center justify-between">
              <div className="text-xs font-medium text-blue-600 uppercase tracking-wide">2. Final Concept Redesign</div>
              <button 
                onClick={() => onGenerateConcept(data.id)}
                disabled={data.isGeneratingKeywordRedesign || !data.competitorImage}
                className="text-xs px-2 py-1 bg-blue-50 text-blue-600 hover:bg-blue-100 rounded font-medium disabled:opacity-50"
              >
                {data.isGeneratingKeywordRedesign ? 'Generating...' : '✨ Create Master'}
              </button>
           </div>
           <ImageZone 
            src={data.keywordRedesignImage} 
            alt={`Master Redesign for ${data.keyword}`}
            onReplace={(f) => handleReplaceImage(f, 'concept')}
            onDelete={() => handleDeleteImage('concept')}
            onClick={() => onImageClick(data.id, 'concept', data.keywordRedesignImage || '')}
          />
          <p className="text-xs text-gray-400 italic mt-1">
            Focus: 2D Holographic Acrylic Ornament style.
          </p>
        </div>

        {/* Col 3: Lifestyle Contexts */}
        <div className="flex flex-col space-y-2">
           <div className="flex items-center justify-between">
              <div className="text-xs font-medium text-brand-600 uppercase tracking-wide">
                 3. Lifestyle Contexts {lifestyleImages.length > 0 && `(${lifestyleImages.length})`}
              </div>
              <button 
                onClick={() => onGenerate(data.id)}
                disabled={data.isGenerating || (!data.keywordRedesignImage && !data.competitorImage)}
                className="text-xs px-2 py-1 bg-brand-50 text-brand-600 hover:bg-brand-100 rounded font-medium disabled:opacity-50"
              >
                {data.isGenerating ? 'Wait...' : (data.keywordRedesignImage ? '📸 Generate Settings' : '📸 Context From Original')}
              </button>
           </div>

           {lifestyleImages.length > 0 ? (
             <div className="grid grid-cols-2 gap-2">
                {lifestyleImages.map((imgSrc, idx) => (
                   <div key={idx} className={idx === 0 && lifestyleImages.length % 2 !== 0 ? "col-span-2" : "col-span-1"}>
                       <ImageZone 
                        src={imgSrc} 
                        alt={`Context ${idx + 1}`}
                        onReplace={(f) => handleReplaceImage(f, 'lifestyle', idx)}
                        onDelete={() => handleDeleteImage('lifestyle', idx)}
                        onClick={() => onImageClick(data.id, 'lifestyle', imgSrc)}
                      />
                   </div>
                ))}
             </div>
           ) : (
             <ImageZone 
                src={undefined} 
                alt="No Lifestyle Mockups"
                onReplace={(f) => handleReplaceImage(f, 'lifestyle')}
                onDelete={() => handleDeleteImage('lifestyle')}
              />
           )}

          <p className="text-xs text-gray-400 italic mt-1">
            Focus: Places existing design into premium interior environments.
          </p>
        </div>

      </div>
    </div>
  );
};

import React, { useState } from 'react';
