async function generateImage(base64Image: string, prompt: string): Promise<string> {
    if (!ai) throw new Error("API Key missing");

    try {
    const response = await retryWithBackoff<GenerateContentResponse>(() => 
      ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { mimeType: 'image/png', data: base64Image } },
            { text: prompt }
          ]
        }
      })
    );

    if (!response.candidates || response.candidates.length === 0) {
       throw new Error("API blocked by safety or returned no image.");
    }

    const candidate = response.candidates[0];
    if (candidate.finishReason === 'SAFETY') {
        throw new Error("Image blocked by safety filters.");
    }

    const imagePart = candidate.content?.parts?.find(p => p.inlineData);
    if (imagePart && imagePart.inlineData) {
      return `data:${imagePart.inlineData.mimeType || 'image/png'};base64,${imagePart.inlineData.data}`;
    }

    throw new Error("No image data found in response.");
  } catch (error) {
    throw error;
  }
}

