import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const apiKey = process.env.API_KEY || '';

// Initialize only if key exists to avoid immediate errors, though usage will check
const ai = apiKey ? new GoogleGenAI({ apiKey }) : null;

const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

/**
 * Helper function to retry async operations with exponential backoff.
 * Handles 429 (Rate Limit), 503 (Overloaded), and 500 (Internal Error).
 */
async function retryWithBackoff<T>(
  fn: () => Promise<T>,
  retries = 3,
  delay = 2000
): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const isRateLimit = 
      error.status === 429 || 
      error.code === 429 || 
      (error.message && typeof error.message === 'string' && error.message.includes("RESOURCE_EXHAUSTED"));

    const isOverloaded =
      error.status === 503 ||
      error.code === 503 ||
      (error.message && typeof error.message === 'string' && error.message.toLowerCase().includes("overloaded"));

    const isInternalError = 
      error.status === 500 ||
      error.code === 500 ||
      (error.message && typeof error.message === 'string' && error.message.includes("Internal error"));

    if (retries > 0 && (isRateLimit || isOverloaded || isInternalError)) {
      const nextDelay = isRateLimit ? Math.max(delay, 4000) : delay;
      console.warn(`API Error (${error.status || error.code || 'Unknown'}). Retrying in ${nextDelay}ms... (${retries} attempts left)`);

      await wait(nextDelay);
      return retryWithBackoff(fn, retries - 1, nextDelay * 2);
    }
    throw error;
  }
}

/**
 * Converts a base64 string or URL to a format suitable for the API.
 */
async function urlToBase64(url: string): Promise<string> {
  if (url.startsWith('data:')) {
    return url.split(',')[1];
  }

  const fetchBlob = async (targetUrl: string): Promise<Blob> => {
    const response = await fetch(targetUrl);
    if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
    const blob = await response.blob();
    // basic validation to ensure we are getting an image
    if (blob.type && !blob.type.startsWith('image/') && blob.type !== 'application/octet-stream') {
         throw new Error(`Invalid content type: ${blob.type}`);
    }
    return blob;
  };

  const strategies = [
    { name: 'Direct', getUrl: (u: string) => u },
    { name: 'Weserv', getUrl: (u: string) => `https://images.weserv.nl/?url=${encodeURIComponent(u)}&output=png&il` },
    { name: 'CorsProxy', getUrl: (u: string) => `https://corsproxy.io/?${encodeURIComponent(u)}` },
    { name: 'AllOrigins', getUrl: (u: string) => `https://api.allorigins.win/raw?url=${encodeURIComponent(u)}` }
  ];

  for (const strategy of strategies) {
    try {
      const blob = await fetchBlob(strategy.getUrl(url));
      return await new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onloadend = () => {
          const result = reader.result as string;
          // Ensure we have a valid base64 string
          if (result && result.includes(',')) {
              resolve(result.split(',')[1]);
          } else {
              reject(new Error("Failed to convert blob to base64"));
          }
        };
        reader.onerror = reject;
        reader.readAsDataURL(blob);
      });
    } catch (e) {
      console.warn(`Fetch strategy '${strategy.name}' failed for ${url}`, e);
    }
  }

  throw new Error("Could not download image. Please upload it directly.");
}

// Interface for the Marketing Analysis Result
interface MarketingAnalysis {
  persona: string;
  benefits: string;
  mood: string;
  props: string;
  context: string;
}

/**
 * Step 1: Analyzes the image to get marketing insights and context.
 */
async function analyzeMarketingInsight(base64Image: string): Promise<MarketingAnalysis> {
  if (!ai) throw new Error("API Key not found.");

  const analysisPrompt = `
    Bạn là AI Agent chuyên “analyze image” để rút ra insight marketing và gợi ý bối cảnh lifestyle/mockup phù hợp.
    Nhiệm vụ: nhìn vào hình ảnh được cung cấp (thường là design/graphic/packaging) và suy luận hợp lý về đối tượng, lợi ích, cảm xúc, mood/vibe, props và bối cảnh.

    Nguyên tắc:
    - Chỉ dựa trên tín hiệu thị giác (chữ trên design, biểu tượng, màu sắc, phong cách minh hoạ, chất liệu giả định, bối cảnh gợi ý).
    - Không bịa chi tiết quá cụ thể.
    - Không nhận diện danh tính người thật trong ảnh.
    - Trả về đúng định dạng output bên dưới, ngắn gọn, dùng tiếng Việt.
    - Không sử dụng hình ảnh của các thương hiệu Trademark (Ví dụ Pepsi, Budweiser,...)

    OUTPUT (bắt buộc đúng các mục, mỗi mục 1–3 dòng):
    Insight sản phẩm:
    - Đối tượng: [mô tả persona cụ thể]
    - Lợi ích chính: [1–3 lợi ích]
    - Cảm xúc muốn tạo: [chọn 1–3 từ]
    - Mood & vibe: {3–6 tính từ, ngăn cách bằng dấu phẩy}
    - Props: {3–6 đạo cụ liên quan, ngăn cách bằng dấu phẩy}
    - Bối cảnh mong muốn: [1 bối cảnh chính + 1 bối cảnh phụ]
  `;

  let responseText = "";
  try {
    const response = await retryWithBackoff<GenerateContentResponse>(() => 
      ai.models.generateContent({
        model: 'gemini-3-flash-preview', // Stronger reasoning model for analysis
        contents: {
          parts: [
            { inlineData: { mimeType: 'image/png', data: base64Image } },
            { text: analysisPrompt }
          ]
        }
      })
    );
    responseText = response.text || "";
  } catch (error) {
    console.warn("Analysis failed, using defaults", error);
    responseText = "";
  }

  // Simple parsing helper (fallback to defaults if parsing fails)
  const extract = (key: string, defaultVal: string) => {
    const regex = new RegExp(`${key}\\s*:?\\s*(.*?)(?=(\\n-|$))`, 'i');
    const match = responseText.match(regex);
    return match ? match[1].trim() : defaultVal;
  };

  return {
    persona: extract("- Đối tượng", "Người yêu thích trang trí nhà cửa"),
    benefits: extract("- Lợi ích chính", "Trang trí, làm quà tặng"),
    mood: extract("- Mood & vibe", "Warm, Cozy, Bright"),
    props: extract("- Props", "Cây xanh, sách, đèn vàng"),
    context: extract("- Bối cảnh mong muốn", "Phòng khách nhiều ánh sáng tự nhiên")
  };
}

/**
 * Analyzes for Concept Design (Slot 2)
 */
async function analyzeForConceptTheme(base64Image: string, keyword: string): Promise<string> {
   if (!ai) throw new Error("API Key not found.");

