const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

/**
 * Enhanced helper function to retry async operations with exponential backoff.
 * Aggressively handles 429 RESOURCE_EXHAUSTED errors common in free tiers.
 */
async function retryWithBackoff<T>(
  fn: () => Promise<T>,
  retries = 5,
  delay = 5000 // Start with a 5s delay to avoid burst limits
): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const isRateLimit = 
      error.status === 429 || 
      error.code === 429 || 
      (error.message && typeof error.message === 'string' && error.message.includes("RESOURCE_EXHAUSTED"));

    const isOverloaded =
      error.status === 503 ||
      error.code === 503 ||
      (error.message && typeof error.message === 'string' && error.message.toLowerCase().includes("overloaded"));

    const isInternalError = 
      error.status === 500 ||
      error.code === 500 ||
      (error.message && typeof error.message === 'string' && error.message.includes("Internal error"));

    if (retries > 0 && (isRateLimit || isOverloaded || isInternalError)) {
      // Much longer wait for rate limits (8s+)
      const nextDelay = isRateLimit ? Math.max(delay, 8000) : delay;
      console.warn(`Gemini API Warning (${error.status || '429'}). Backing off ${nextDelay}ms...`);

      await wait(nextDelay);
      return retryWithBackoff(fn, retries - 1, nextDelay * 1.5);
    }
    throw error;
  }
}

