    temperature: 0.4 // Slightly higher for creative redesign
  });
};

export const editImage = async (
  originalImageSrc: string,
  instruction: string
): Promise<string> => {
  let img: { data: string; mimeType: string };
  try {
    img = await urlToBase64(originalImageSrc);
  } catch (e: any) {
    throw new Error(`Image processing failed: ${e.message}`);
  }

  const prompt = `
  PRODUCT PHOTO EDIT: ${instruction}
  Constraint: Keep the product identity (Holo Acrylic Ornament) identical. Only change specific elements mentioned in the instruction.
  Style: Premium Acrylic Ornament.
  Output: Image only.
  `;

  return generateImage(img.data, img.mimeType, prompt, {
    systemInstruction: "You are a helpful product photo editor."
  });
};

interface GenerateImageOptions {
  systemInstruction?: string;
  temperature?: number;
}

async function generateImage(
  base64Data: string, 
  mimeType: string, 
  prompt: string, 
  options: GenerateImageOptions = {}
): Promise<string> {
  // Always create a fresh instance to capture the latest API_KEY from the environment/dialog
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const { 
    systemInstruction = "You are a professional AI artist.", 
    temperature = 0.2 
  } = options;

  const response = await retryWithBackoff<GenerateContentResponse>(() => 
    ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      config: {
        // Enforce rules via systemInstruction
        systemInstruction: {
          parts: [{ text: systemInstruction }]
        },
        // Force IMAGE modality
        responseModalities: [Modality.IMAGE],
        temperature: temperature
      },
      contents: {
        parts: [
          { inlineData: { mimeType: mimeType, data: base64Data } },
          { text: prompt }
        ]
      }
    })
  );

  if (!response.candidates || response.candidates.length === 0) {
     throw new Error("No image generated.");
  }

  const candidate = response.candidates[0];
  if (candidate.finishReason === 'SAFETY') {
      throw new Error("Content filtered for safety.");
  }

  if (candidate.content && candidate.content.parts) {
    for (const part of candidate.content.parts) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType || 'image/png'};base64,${part.inlineData.data}`;
      }
    }
  }

  throw new Error("Failed to extract image from response.");
}
